'use client';

import React, { useEffect, useState } from 'react';
import { Sidebar } from '@/components/layout';
import { ParticleSystem, MouseReactiveGlow, VHSEffect, CRTEffect, WeatherEffect } from '@/components/effects';
import { User, UserPreferences } from '@/types';

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const [user, setUser] = useState<User | undefined>(undefined);
  const [preferences, setPreferences] = useState<UserPreferences | null>(null);

  useEffect(() => {
    // Read user from localStorage if it exists
    const storedUser = localStorage.getItem('auth_user');
    if (storedUser) {
      try {
        setUser(JSON.parse(storedUser));
      } catch (e) {
        console.error('Failed to parse user', e);
      }
    }

    // Read preferences from localStorage
    const storedPrefs = localStorage.getItem('user_preferences');
    if (storedPrefs) {
      try {
        setPreferences(JSON.parse(storedPrefs));
      } catch (e) {
        console.error('Failed to parse preferences', e);
      }
    } else {
      // Default preferences
      const defaultPrefs: UserPreferences = {
        theme: 'neon-purple',
        audioVolume: 30,
        audioMuted: false,
        performanceMode: false,
        reducedMotion: false,
        vhsEffect: false,
        crtEffect: false,
        particleEffect: true,
        mouseGlow: true,
        weatherEffect: false,
        notifications: {
          events: true,
          messages: true,
          updates: true,
          frequency: 'all',
        },
      };
      setPreferences(defaultPrefs);
    }
  }, []);

  return (
    <div className="min-h-screen bg-dark-navy text-white relative overflow-x-hidden">
      {/* Background Visual Effects based on preferences */}
      {preferences && (
        <>
          <ParticleSystem enabled={preferences.particleEffect} particleCount={preferences.performanceMode ? 40 : 100} />
          <MouseReactiveGlow enabled={preferences.mouseGlow} />
          <VHSEffect enabled={preferences.vhsEffect} />
          <CRTEffect enabled={preferences.crtEffect} />
          <WeatherEffect enabled={preferences.weatherEffect} />
        </>
      )}

      {/* Sidebar Navigation */}
      <Sidebar />

      {/* Main Content Area with left margin for sidebar */}
      <div className="ml-32">
        {children}
      </div>
    </div>
  );
}
